      "status": "pending"
    },
    {
      "description": "Check the number of rows after the merge and report any unexpected result.",
      "r_code": "local({\n  cat(\"Rows after merge: \", nrow(merged_data), \"\\n\")\n  cat(\"Date range: \", range(merged_data$Date), \"\\n\")\n})",
      "considerations": "If the row count is zero or far from expected, investigate key type mismatches with `str(spx_daily_5y$Date)` and `str(bitcoin_daily_5y$Date)`.",
      "status": "pending"
    },
    {
      "description": "Calculate daily returns for both assets and add them as new columns.",
      "r_code": "merged_data <- merged_data %>%\n  arrange(Date) %>%\n  mutate(\n    SPX_Return = (SPX_Close - lag(SPX_Close)) / lag(SPX_Close),\n    BTC_Return = (BTC_Close - lag(BTC_Close)) / lag(BTC_Close)\n  )",
      "considerations": "Make sure the data is sorted by Date before using `lag`. The first row will have NA returns.",
      "status": "pending"
    },
    {
      "description": "Reshape the returns into long format for easy plotting.",
      "r_code": "returns_long <- merged_data %>%\n  select(Date, SPX_Return, BTC_Return) %>%\n  pivot_longer(cols = c(SPX_Return, BTC_Return),\n               names_to = \"Asset\",\n               values_to = \"Return\")",
      "considerations": "This temporary object will be removed after plotting (wrapped in `local`).",
      "status": "pending"
    },
    {
      "description": "Create a line plot of the two return series over time.",
      "r_code": "local({\n  p <- ggplot(returns_long, aes(x = Date, y = Return, color = Asset)) +\n    geom_line(alpha = 0.7) +\n    labs(title = \"Daily Returns: S&P 500 vs Bitcoin\",\n         x = \"Date\",\n         y = \"Return\",\n         color = \"Asset\") +\n    theme_minimal()\n  print(p)\n  rm(returns_long)  # cleanup temporary data used for plotting\n})",
      "considerations": "The plot is displayed as a side‑effect; no new objects are left in the global environment.",
      "status": "pending"
    },
    {
      "description": "Remove intermediate renamed data frames that are no longer needed.",
      "r_code": "rm(spx_renamed, btc_renamed)",
      "considerations": "Keeps only the original source data frames and the final `merged_data` (which the user may want to keep).",
      "status": "pending"
    }
  ]
}

